import { useNavigate } from "react-router-dom";
import "../css/Topbar.css";

function Topbar() {
  const navigate = useNavigate();

  const handleLogout = () => {
    localStorage.removeItem("kirana_token");
    localStorage.removeItem("kirana_admin");
    navigate("/login");
  };

  return (
    <header className="topbar">
      <h1 className="topbar-title">Kirana Store CRM</h1>
      <button type="button" className="btn btn-sm btn-outline-light topbar-logout" onClick={handleLogout}>
        Logout
      </button>
    </header>
  );
}

export default Topbar;
